   117→char* MiniShell::HandleCommand() {
   118→    EnableMode();
   119→    ShowHeader();
   120→
   121→    char seq[5];
   122→    memset(&command, 0x0, MAX_CMD_LENGTH);
   123→    memset(&seq, 0x0, sizeof(seq));
   124→    while (1) {
   125→        int ch = getchar();
   126→        if (ch == EOF) break;
   127→
   128→        seq[0] = (char)ch;
   129→        if (seq[0] == KEYCODE_ESC) {
   130→            seq[1] = (char)getchar();
   131→            if (seq[1] != 0x5B) break;
   132→            seq[2] = (char)getchar();
   133→            if (!strcmp(seq, ARROW_UP)) {
   134→                ShowHistory(true);
   135→            } else if (!strcmp(seq, ARROW_DOWN)) {
   136→                ShowHistory(false);
   137→            } else if (!strcmp(seq, ARROW_RIGHT)) {
   138→                CursorMove(1, 0);
   139→            } else if (!strcmp(seq, ARROW_LEFT)) {
   140→                CursorMove(-1, 0);
   141→            } else {
   142→                if (!strcmp(seq, KEY_HOME)) {
   143→                    if (curX - minX > 1) {
   144→                        CursorMove(minX + 1 - curX, 0);
   145→                    }
   146→                } else if (!strcmp(seq, KEY_END)) {
   147→                    if (curX < totalX) {
   148→                        CursorMove(totalX - curX, 0);
   149→                    }
   150→                } else {
   151→                    // do nothing
   152→                    break;
   153→                }
   154→            }
   155→        } else {
   156→            if (seq[0] == KEYCODE_ENTER || seq[0] == KEYCODE_LF) {
   157→                SaveHistory(command);
   158→                ENTER();
   159→                break;
   160→            }
   161→
   162→            if (seq[0] == KEYCODE_TAB) {
   163→                continue;
   164→            } else if (seq[0] == KEYCODE_BACK || seq[0] == KEYCODE_DEL) {
   165→                if (curX > minX + 1) {
   166→                    for (int i = curX - 1; i < totalX; ++i) {
   167→                        command[i - (minX + 1)] = command[i + 1 - (minX + 1)];
   168→                    }
   169→                    command[totalX - 1 - (minX + 1)] = '\0';
   170→                    uint32_t bx = curX == totalX ? curX : curX - 1;
   171→                    ClearLine();
   172→                    ShowCommand();
   173→                    CursorMove(bx - curX, 0);
   174→                }
   175→            } else {
   176→                if (totalX - minX < MAX_CMD_LENGTH) {
   177→                    printf("%c", seq[0]);
   178→                    char backup = command[curX - (minX + 1)];
   179→                    command[curX - (minX + 1)] = seq[0];
   180→                    curX++;
   181→                    totalX++;
   182→                    int off = 0;
   183→                    for (int i = curX; i < totalX; ++i) {
   184→                        std::swap(backup, command[i - (minX + 1)]);
   185→                        printf("%c", command[i - (minX + 1)]);
   186→                        off++;
   187→                        curX++;
   188→                    }
   189→                    if (off) CursorMove(-off, 0);
   190→                }
   191→            }
   192→        }
   193→    }
   194→    DisableMode();
